  return result;
}

{
#ifndef CURL_DISABLE_PROXY
  return (cf->cft == &Curl_cft_ssl_proxy);
#else
  (void)cf;
  return FALSE;
#endif
}

{
#ifdef CURL_DISABLE_PROXY
  (void)cf;
